INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' com referência às declarações de IMT entregues no ano civil anterior, a identificação dos sujeitos passivos e o valor de imposto liquidado, relativamente a factos tributários localizados nesses municípios, por sujeito passivo;
